#include<bits/stdc++.h>
using namespace std;
long long c,v[15],dp[100010][21],a[100010];
long long p[15]={1,10,100,1000,10000,100000,1000000,10000000,100000000,1000000000};
int main()
{
    int c,t;
    scanf("%d%d",&c,&t);
    while(t--)
    {
        memset(dp,0,sizeof(dp));
        string n;
        cin>>n;
        for(int i=1;i<=9;i++)
        {
            scanf("%lld",&v[i]);
        }
        long long l=n.length();
        for(long long i=0;i<l;i++)
        {
            a[i+1]=n[i]-'0';
        }
        long long sum=0;
        for(long long i=1;i<=l;i++)
        {
            sum+=v[a[i]];
        }
        for(long long i=l;i>=1;i--)
        {
            for(long long j=1;j<=min(9ll,l-i+1);j++)
            {
                dp[i][j]=max(dp[i+1][j],dp[i+1][j-1]+v[a[i]]-p[j-1]*a[i]);
            }
        }
        long long ans=0;
        for(long long i=1;i<=9;i++)
        {
            ans=max(ans,dp[1][i]);
        }
        printf("%lld\n",sum-ans);
    }
    return 0;
}
